5328 Value *llvm::isBytewiseValue(Value *V, const DataLayout &DL) {
5329 
5330   // All byte-wide stores are splatable, even of arbitrary variables.
5331   if (V->getType()->isIntegerTy(8))
5332     return V;
5333 
5334   LLVMContext &Ctx = V->getContext();
5335 
5336   // Undef don't care.
5337   auto *UndefInt8 = UndefValue::get(Type::getInt8Ty(Ctx));
5338   if (isa<UndefValue>(V))
5339     return UndefInt8;
5340 
5341   // Return Undef for zero-sized type.
5342   if (DL.getTypeStoreSize(V->getType()).isZero())
5343     return UndefInt8;
5344 
5345   Constant *C = dyn_cast<Constant>(V);
5346   if (!C) {
5347     // Conceptually, we could handle things like:
5348     //   %a = zext i8 %X to i16
5349     //   %b = shl i16 %a, 8
5350     //   %c = or i16 %a, %b
5351     // but until there is an example that actually needs this, it doesn't seem
5352     // worth worrying about.
5353     return nullptr;
5354   }
5355 
5356   // Handle 'null' ConstantArrayZero etc.
5357   if (C->isNullValue())
5358     return Constant::getNullValue(Type::getInt8Ty(Ctx));
5359 
5360   // Constant floating-point values can be handled as integer values if the
5361   // corresponding integer value is "byteable".  An important case is 0.0.
5362   if (ConstantFP *CFP = dyn_cast<ConstantFP>(C)) {
5363     Type *Ty = nullptr;
5364     if (CFP->getType()->isHalfTy())
5365       Ty = Type::getInt16Ty(Ctx);
5366     else if (CFP->getType()->isFloatTy())
5367       Ty = Type::getInt32Ty(Ctx);
5368     else if (CFP->getType()->isDoubleTy())
5369       Ty = Type::getInt64Ty(Ctx);
5370     // Don't handle long double formats, which have strange constraints.
5371     return Ty ? isBytewiseValue(ConstantExpr::getBitCast(CFP, Ty), DL)
5372               : nullptr;
5373   }
5374 
5375   // We can handle constant integers that are multiple of 8 bits.
5376   if (ConstantInt *CI = dyn_cast<ConstantInt>(C)) {
5377     if (CI->getBitWidth() % 8 == 0) {
5378       assert(CI->getBitWidth() > 8 && "8 bits should be handled above!");
5379       if (!CI->getValue().isSplat(8))
5380         return nullptr;
5381       return ConstantInt::get(Ctx, CI->getValue().trunc(8));
5382     }
5383   }
5384 
5385   if (auto *CE = dyn_cast<ConstantExpr>(C)) {
5386     if (CE->getOpcode() == Instruction::IntToPtr) {
5387       if (auto *PtrTy = dyn_cast<PointerType>(CE->getType())) {
5388         unsigned BitWidth = DL.getPointerSizeInBits(PtrTy->getAddressSpace());
5389         if (Constant *Op = ConstantFoldIntegerCast(
5390                 CE->getOperand(0), Type::getIntNTy(Ctx, BitWidth), false, DL))
5391           return isBytewiseValue(Op, DL);
5392       }
5393     }
5394   }
5395 
5396   auto Merge = [&](Value *LHS, Value *RHS) -> Value * {
5397     if (LHS == RHS)
5398       return LHS;
5399     if (!LHS || !RHS)
5400       return nullptr;
5401     if (LHS == UndefInt8)
5402       return RHS;
5403     if (RHS == UndefInt8)
5404       return LHS;
5405     return nullptr;
5406   };
5407 
5408   if (ConstantDataSequential *CA = dyn_cast<ConstantDataSequential>(C)) {
5409     Value *Val = UndefInt8;
5410     for (unsigned I = 0, E = CA->getNumElements(); I != E; ++I)
5411       if (!(Val = Merge(Val, isBytewiseValue(CA->getElementAsConstant(I), DL))))
5412         return nullptr;
5413     return Val;
5414   }
5415 
5416   if (isa<ConstantAggregate>(C)) {
5417     Value *Val = UndefInt8;
5418     for (unsigned I = 0, E = C->getNumOperands(); I != E; ++I)
5419       if (!(Val = Merge(Val, isBytewiseValue(C->getOperand(I), DL))))
5420         return nullptr;
5421     return Val;
5422   }
5423 
5424   // Don't try to handle the handful of other constants.
5425   return nullptr;
5426 }
